N, M = map(int, input().split())
S = list(map(int, input().split()))
T = list(map(int, input().split()))
MOD = 10**9 + 7

def count_subsequences(A, B):
    n, m = len(A), len(B)
    dp = [[0] * (m + 1) for _ in range(n + 1)]
    for i in range(n):
        for j in range(m):
            if A[i] == B[j]:
                dp[i + 1][j + 1] = (dp[i][j] + 1) % MOD
            else:
                dp[i + 1][j + 1] = dp[i + 1][j]
    return dp[-1][-1]

result = count_subsequences(S, T)
print(result)
